// Normalize incoming form fields — handles Typeform, custom forms, or direct API calls
const body = $input.item.json.body || $input.item.json;

return {
  json: {
    name: body.name || body.full_name || body.respondent_name || 'Unknown',
    email: body.email || body.email_address || '',
    company: body.company || body.company_name || body.organization || '',
    role: body.role || body.job_title || body.title || '',
    message: body.message || body.notes || body.comment || '',
    phone: body.phone || body.phone_number || '',
    source: body.utm_source || body.source || 'direct',
    raw: body
  }
};

