parameters.jsCode:
const aiResult = JSON.parse($input.item.json.choices[0].message.content);
const lead = $('Normalize Lead Data').item.json;

return {
  json: {
    // Lead fields for Google Sheets columns
    name: lead.name,
    email: lead.email,
    company: lead.company,
    role: lead.role,
    message: lead.message,
    phone: lead.phone,
    source: lead.source,
    // AI scoring fields
    ai_score: aiResult.score,
    ai_tier: aiResult.tier,
    ai_reasoning: aiResult.reasoning,
    ai_next_action: aiResult.next_action,
    // Metadata
    captured_at: new Date().toISOString(),
    date: new Date().toLocaleDateString('en-US'),
    time: new Date().toLocaleTimeString('en-US')
  }
};

